{
  "type": "DRAG_FILL",
  "data": {
    "lessonText": "Test your skills with this gamified challenge.",
    "challenges": [
      {
        "instruction": "Fill in the blanks to complete the function.",
        "codeTemplate": "def calculate_score(player_score, bonus):\n    return player_score + ___ + ___",
        "options": ["bonus", "player_score", "level_up", "multiplier"],
        "correctAnswer": "bonus,player_score",
        "explanation": "The function adds the player's score to the bonus and the player's score again."
      },
      {
        "instruction": "Complete the conditional statement.",
        "codeTemplate": "if player_health > ___:\n    print('Player is healthy')\nelse:\n    print('Player needs healing')",
        "options": ["50", "100", "75", "25"],
        "correctAnswer": "50",
        "explanation": "The player is considered healthy if their health is above 50."
      },
      {
        "instruction": "Fill in the missing variable.",
        "codeTemplate": "def level_up(current_level):\n    new_level = current_level + ___\n    return new_level",
        "options": ["1", "2", "3", "4"],
        "correctAnswer": "1",
        "explanation": "The player levels up by 1 each time the function is called."
      },
      {
        "instruction": "Complete the loop to iterate through scores.",
        "codeTemplate": "for score in scores:\n    total += ___\nprint(total)",
        "options": ["score", "total", "points", "level"],
        "correctAnswer": "score",
        "explanation": "The loop adds each score to the total."
      }
    ]
  }
}
